INSERT INTO public.news_articles (slug, title, category, excerpt, content, featured, published, published_at, meta_title, meta_description, keywords, og_image_url, author_name) VALUES ('talitrix-a-title-sponsor-of-georgia-association-of-black-county-officials-presidents-reception-advancing-health-equality', $tf2cloxh1$Talitrix: A Title Sponsor of Georgia Association of Black County Officials President's Reception Advancing Health Equality$tf2cloxh1$, 'Announcement', $tl8nwemld$Atlanta, GA - December 23, 2023 - Talitrix, a pioneering force in the criminal justice industry, proudly announces its role as one of the esteemed Title Sponsors for the Georgia Association of Black County Officials Presidents Reception. This holiday-themed event, held on Sunday, December 10, 2023, at the renowned Lowcountry Steak restaurant on 1010 W. Peachtree St. NW in Atlanta, celebrated the tireless efforts of county officials across Georgia, all under the banner of Advancing Health Equalit$tl8nwemld$, $tljehpg25$Atlanta, GA - December 23, 2023 - Talitrix, a pioneering force in the criminal justice industry, proudly announces its role as one of the esteemed Title Sponsors for the Georgia Association of Black County Officials Presidents Reception. This holiday-themed event, held on Sunday, December 10, 2023, at the renowned Lowcountry Steak restaurant on 1010 W. Peachtree St. NW in Atlanta, celebrated the tireless efforts of county officials across Georgia, all under the banner of Advancing Health Equality.

The evening was a harmonious blend of festivity and recognition, as Talitrix joined hands with the Georgia Association of Black County Officials (GABCO) to honor exemplary public servants who have made significant contributions to their communities. We extend our warmest congratulations to the distinguished honorees, recognized for their outstanding commitment and dedication:

• Fani T. Willis - Fulton County District Attorney

• Sherry Boston - Dekalb County District Attorney

• Keith Gammage - Fulton County Solicitor - General

• Charles Brooks - Clayton Solicitor - General

• Tammi Hayward - State Court Judge - Clayton

• Kenya Johnson - Fulton County Probate Court Judge

• Dick Anderson - Fulton County County Manager

• Arthur E. Ferdinand - Fulton County Tax Commissioner

• Sonya Halpern - Georgia State Senator

• Tanya Miller - Georgia House Representative

• Natalie Hall - Fulton County Commissioner

• Melody Maddox - Dekalb County Sheriff

• Craig Owens - Cobb County Sheriff

The event was masterfully hosted by Maria Boynton, serving as the mistress of ceremonies, accompanied by the soulful music of the Darryl Peek band. The culinary delights, crafted by Chef G. Garvin & team, added a flavorful touch to the evening's festivities, creating an atmosphere of warmth and camaraderie.

Talitrix acknowledges the Georgia Association of Black County Officials for their unwavering commitment to fostering health equality and salutes President Marvin Arrington, Jr., Fulton County Commissioner, for providing the opportunity to be a title sponsor of this exceptional event.

At Talitrix, we are on a mission to revolutionize the criminal justice industry. We firmly believe that the right technologies can reunite families and safeguard communities.$tljehpg25$, false, true, '2024-01-03T20:57:00.005Z', $t55m1ciqf$Talitrix: A Title Sponsor of Georgia Association of Black County Officials President's Reception Advancing Health Equali$t55m1ciqf$, 'Atlanta, GA - December 23, 2023 - Talitrix, a pioneering force in the criminal justice industry, proudly announces its role as one of the esteemed Title Sponsor', NULL, '/news-images/talitrix-a-title-sponsor-of-georgia-association-of-black-county-officials-presidents-reception-advancing-health-equality.jpg', 'Avery Finley');